{"file_text": "datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

model User {
  id            String    @id @default(cuid())
  name          String?
  email         String?   @unique
  password      String?
  role          Role      @default(CUSTOMER)
  restaurants   Restaurant[]
  orders        Order[]
}

enum Role {
  CUSTOMER
  OWNER
  ADMIN
}

model Restaurant {
  id          String     @id @default(cuid())
  name        String
  description String?
  address     String?
  ownerId     String
  owner       User       @relation(fields: [ownerId], references: [id])
  menuItems   MenuItem[]
}

model MenuItem {
  id           String     @id @default(cuid())
  name         String
  description  String?
  price        Float
  restaurantId String
  restaurant   Restaurant @relation(fields: [restaurantId], references: [id])
  orderItems   OrderItem[]
}

model Order {
  id           String      @id @default(cuid())
  status       OrderStatus @default(PENDING)
  total        Float
  userId       String
  user         User        @relation(fields: [userId], references: [id])
  items        OrderItem[]
  createdAt    DateTime    @default(now())
}

enum OrderStatus {
  PENDING
  PREPARING
  COMPLETED
  CANCELLED
}

model OrderItem {
  id         String   @id @default(cuid())
  quantity   Int
  orderId    String
  order      Order    @relation(fields: [orderId], references: [id])
  menuItemId String
  menuItem   MenuItem @relation(fields: [menuItemId], references: [id])
}
", "path": "/workspace/prisma/schema.prisma", "command": "create"}
